starterCode.css:
body { background: #f6f7fb; color: #20242d; font-family: system-ui, sans-serif; padding: 24px; }
.panel { max-width: 620px; margin: 0 auto; }
label { display: grid; gap: 6px; max-width: 220px; margin-bottom: 14px; font-weight: 700; }
select { padding: 8px; }
#contador { font-weight: 700; }
#tareas { list-style: none; padding: 0; display: grid; gap: 8px; }
.tarea { cursor: pointer; padding: 12px 14px; background: white; border: 1px solid #d8deea; border-radius: 8px; }
.urgente { border-color: #d33; background: #fff2f2; }
.completada { text-decoration: line-through; opacity: .55; }
